CREATE TABLE dc_ai_knowledge_gap (id BIGINT PRIMARY KEY AUTO_INCREMENT, normalized_topic VARCHAR(255) NOT NULL, sample_question TEXT, occurrence_count INT NOT NULL DEFAULT 1, low_score_count INT NOT NULL DEFAULT 0, risk_level VARCHAR(16) NOT NULL DEFAULT 'low', status VARCHAR(32) NOT NULL DEFAULT 'pending', last_seen_at DATETIME NOT NULL, create_time DATETIME NOT NULL, update_time DATETIME NOT NULL, UNIQUE KEY uk_dc_ai_gap_topic (normalized_topic), KEY idx_dc_ai_gap_status_seen (status,last_seen_at));
CREATE TABLE dc_ai_research_source (id BIGINT PRIMARY KEY AUTO_INCREMENT, gap_id BIGINT NOT NULL, title VARCHAR(500) NOT NULL, url VARCHAR(1000) NOT NULL, publisher VARCHAR(255), retrieved_at DATETIME NOT NULL, summary TEXT, authority_score INT, create_time DATETIME NOT NULL, KEY idx_dc_ai_source_gap (gap_id));
CREATE TABLE dc_ai_content_candidate (id BIGINT PRIMARY KEY AUTO_INCREMENT, gap_id BIGINT NOT NULL, content_type VARCHAR(32) NOT NULL, title VARCHAR(500) NOT NULL, content TEXT NOT NULL, tags VARCHAR(500), risk_level VARCHAR(16) NOT NULL, ai_review_json TEXT, status VARCHAR(32) NOT NULL DEFAULT 'generated', create_time DATETIME NOT NULL, update_time DATETIME NOT NULL, KEY idx_dc_ai_candidate_gap_status (gap_id,status));
CREATE TABLE dc_ai_content_publish_log (id BIGINT PRIMARY KEY AUTO_INCREMENT, candidate_id BIGINT NOT NULL, mf_ep_content_id BIGINT NULL, action VARCHAR(32) NOT NULL, operator VARCHAR(64), remark VARCHAR(500), create_time DATETIME NOT NULL, KEY idx_dc_ai_publish_candidate (candidate_id,create_time));
